head.b:skin:
/* ============================================================
   MI BIBLIA 365 — MVP STYLES
   Brief: Secciones 4, 19, 20
   ============================================================ */

/* ── CSS Variables: Light Theme ── */
:root {
  --bg: #FAF8F4;
  --bg-alt: #F0EDE6;
  --surface: #FFFFFF;
  --surface-hover: #F5F3EE;
  --primary: #1A2332;
  --primary-light: #2C3E50;
  --accent: #C4963A;
  --accent-light: #D4A94E;
  --accent-bg: rgba(196,150,58,0.08);
  --text: #1A2332;
  --text-secondary: #5C6370;
  --text-muted: #9CA3AF;
  --border: #E5E1D8;
  --border-light: #F0EDE6;
  --success: #4A7C59;
  --success-bg: rgba(74,124,89,0.1);
  --error: #B85450;
  --shadow: 0 1px 3px rgba(26,35,50,0.06), 0 1px 2px rgba(26,35,50,0.04);
  --shadow-md: 0 4px 12px rgba(26,35,50,0.08), 0 2px 4px rgba(26,35,50,0.04);
  --shadow-lg: 0 12px 40px rgba(26,35,50,0.1);
  --radius: 12px;
  --radius-sm: 8px;
  --radius-lg: 16px;
  --font-display: 'Playfair Display', Georgia, serif;
  --font-body: 'Nunito Sans', -apple-system, BlinkMacSystemFont, sans-serif;
  --nav-height: 64px;
  --bottom-nav-height: 68px;
  --max-width: 720px;
  --transition: 0.2s ease;
}

/* ── Dark Theme (Sección 19.3) ── */
[data-theme="dark"] {
  --bg: #0F1117;
  --bg-alt: #161822;
  --surface: #1C1F2E;
  --surface-hover: #242738;
  --primary: #E8C547;
  --primary-light: #D4A94E;
  --accent: #E8C547;
  --accent-light: #F0D46A;
  --accent-bg: rgba(232,197,71,0.1);
  --text: #E8E6E1;
  --text-secondary: #A0A4B0;
  --text-muted: #6B6F7C;
  --border: #2A2D3C;
  --border-light: #222536;
  --success: #5FAF6B;
  --success-bg: rgba(95,175,107,0.12);
  --error: #E06B67;
  --shadow: 0 1px 3px rgba(0,0,0,0.3);
  --shadow-md: 0 4px 12px rgba(0,0,0,0.3);
  --shadow-lg: 0 12px 40px rgba(0,0,0,0.4);
}

/* ── Reset & Base ── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html {
  font-size: 16px;
  -webkit-text-size-adjust: 100%;
  scroll-behavior: smooth;
}

body {
  font-family: var(--font-body);
  background: var(--bg);
  color: var(--text);
  line-height: 1.65;
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

a { color: var(--accent); text-decoration: none; transition: color var(--transition); }
a:hover { color: var(--accent-light); }

img { max-width: 100%; height: auto; display: block; }

button, input, select, textarea {
  font-family: inherit;
  font-size: inherit;
  border: none;
  outline: none;
  background: none;
}

button { cursor: pointer; }

/* ── Hide Blogger Default Elements (Sección 4: NO debe parecer blog) ── */
html body .navbar,
html body .header-inner,
html body #header,
html body .blog-feeds,
html body #footer,
html body .footer-outer,
html body .post,
html body .date-header,
html body .post-footer,
html body .blog-pager,
html body .feed-links,
html body .sidebar,
html body #sidebar,
html body .comments,
html body #comments,
html body .comment-form,
html body .widget,
html body .section,
html body #Attribution1,
html body .blogger-labels,
html body .status-msg-wrap,
html body .tabs-outer,
html body .header-outer,
html body .content-outer,
html body .content-inner,
html body .main-outer,
html body .footer-inner,
html body .centered-top-placeholder,
html body .centered-top-container {
  display: none !important;
  visibility: hidden !important;
  height: 0 !important;
  overflow: hidden !important;
  margin: 0 !important;
  padding: 0 !important;
}

/* Keep our app visible */
html body #mb365-app,
html body #mb365-app * {
  display: revert;
  visibility: visible;
}

/* ── App Container ── */
#mb365-app {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

/* ── Header (Sección 12.1) ── */
.mb-header {
  position: sticky;
  top: 0;
  z-index: 100;
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  height: var(--nav-height);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

.mb-header__inner {
  max-width: 960px;
  margin: 0 auto;
  padding: 0 16px;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.mb-header__brand {
  display: flex;
  align-items: center;
  gap: 10px;
}

.mb-header__brand i { color: var(--accent); }

.mb-header__brand h1 {
  font-family: var(--font-display);
  font-size: 1.15rem;
  font-weight: 600;
  color: var(--text);
  letter-spacing: -0.01em;
}

.mb-header__brand span {
  font-family: var(--font-body);
  font-size: 0.72rem;
  color: var(--text-muted);
  letter-spacing: 0.08em;
  text-transform: uppercase;
  display: block;
  margin-top: -2px;
}

.mb-header__actions {
  display: flex;
  align-items: center;
  gap: 4px;
}

.mb-nav-desktop {
  display: none;
  align-items: center;
  gap: 2px;
  margin-right: 12px;
}

.mb-nav-desktop a {
  padding: 6px 12px;
  border-radius: var(--radius-sm);
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--text-secondary);
  transition: all var(--transition);
  white-space: nowrap;
}

.mb-nav-desktop a:hover,
.mb-nav-desktop a.active {
  color: var(--text);
  background: var(--accent-bg);
}

.icon-btn {
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  color: var(--text-secondary);
  transition: all var(--transition);
}

.icon-btn:hover {
  background: var(--bg-alt);
  color: var(--text);
}

/* ── Main Content ── */
.mb-main {
  flex: 1;
  padding-bottom: calc(var(--bottom-nav-height) + 20px);
}

.mb-page {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 20px 16px;
  display: none;
  animation: fadeIn 0.3s ease;
}

.mb-page.active { display: block; }

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}

/* ── Bottom Navigation (Sección 12.2: mobile-first) ── */
.mb-bottom-nav {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  z-index: 100;
  background: var(--surface);
  border-top: 1px solid var(--border);
  height: var(--bottom-nav-height);
  display: flex;
  align-items: center;
  justify-content: space-around;
  padding-bottom: env(safe-area-inset-bottom, 0);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

.mb-bottom-nav a {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  padding: 6px 0;
  min-width: 56px;
  color: var(--text-muted);
  transition: color var(--transition);
  -webkit-tap-highlight-color: transparent;
}

.mb-bottom-nav a span {
  font-size: 0.62rem;
  font-weight: 600;
  letter-spacing: 0.02em;
}

.mb-bottom-nav a.active {
  color: var(--accent);
}

.mb-bottom-nav a.active i,
.mb-bottom-nav a.active svg { stroke-width: 2.2; }

/* ── Typography ── */
.page-title {
  font-family: var(--font-display);
  font-size: 1.75rem;
  font-weight: 600;
  color: var(--text);
  margin-bottom: 4px;
  letter-spacing: -0.02em;
}

.page-subtitle {
  font-size: 0.95rem;
  color: var(--text-secondary);
  margin-bottom: 24px;
  line-height: 1.5;
}

.section-title {
  font-family: var(--font-display);
  font-size: 1.1rem;
  font-weight: 600;
  color: var(--text);
  margin-bottom: 12px;
}

/* ── Cards ── */
.card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 20px;
  box-shadow: var(--shadow);
  transition: all var(--transition);
}

.card:hover { box-shadow: var(--shadow-md); }

.card + .card { margin-top: 12px }

/* ── Daily Verse (Sección 10) ── */
.daily-verse {
  background: linear-gradient(135deg, var(--primary) 0%, var(--primary-light) 100%);
  color: #FFFFFF;
  border-radius: var(--radius-lg);
  padding: 28px 24px;
  margin-bottom: 24px;
  position: relative;
  overflow: hidden;
}

.daily-verse::before {
  content: '';
  position: absolute;
  top: -30%;
  right: -20%;
  width: 200px;
  height: 200px;
  background: radial-gradient(circle, rgba(232,197,71,0.12) 0%, transparent 70%);
  border-radius: 50%;
}

.daily-verse__label {
  font-size: 0.68rem;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  opacity: 0.7;
  margin-bottom: 12px;
  font-weight: 600;
}

.daily-verse__text {
  font-family: var(--font-display);
  font-size: 1.18rem;
  font-weight: 400;
  line-height: 1.6;
  margin-bottom: 14px;
  font-style: italic;
  position: relative;
  z-index: 1;
}

.daily-verse__ref {
  font-size: 0.82rem;
  font-weight: 600;
  opacity: 0.85;
  position: relative;
  z-index: 1;
}

.daily-verse__theme {
  font-size: 0.72rem;
  opacity: 0.55;
  margin-top: 6px;
  font-style: italic;
}

/* ── Buttons ── */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px 24px;
  border-radius: var(--radius-sm);
  font-weight: 600;
  font-size: 0.9rem;
  transition: all var(--transition);
  min-height: 48px;
  letter-spacing: 0.01em;
}

.btn-primary {
  background: var(--accent);
  color: #FFFFFF;
  box-shadow: 0 2px 8px rgba(196,150,58,0.25);
}

.btn-primary:hover {
  background: var(--accent-light);
  box-shadow: 0 4px 16px rgba(196,150,58,0.35);
  transform: translateY(-1px);
}

.btn-secondary {
  background: var(--bg-alt);
  color: var(--text);
  border: 1px solid var(--border);
}

.btn-secondary:hover {
  background: var(--surface-hover);
  border-color: var(--accent);
}

.btn-ghost {
  background: transparent;
  color: var(--accent);
}

.btn-ghost:hover { background: var(--accent-bg); }

.btn-full { width: 100%; }

.btn-group {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

/* ── Progress Bar (Sección 19.4) ── */
.progress-bar {
  background: var(--bg-alt);
  border-radius: 100px;
  height: 8px;
  overflow: hidden;
  margin: 12px 0;
}

.progress-bar__fill {
  height: 100%;
  background: linear-gradient(90deg, var(--accent) 0%, var(--accent-light) 100%);
  border-radius: 100px;
  transition: width 0.6s cubic-bezier(0.22, 1, 0.36, 1);
  min-width: 0;
}

.progress-label {
  font-size: 0.78rem;
  color: var(--text-secondary);
  display: flex;
  justify-content: space-between;
  margin-top: 4px;
}

/* ── Form Elements ── */
.form-group { margin-bottom: 16px; }

.form-label {
  display: block;
  font-size: 0.82rem;
  font-weight: 600;
  color: var(--text-secondary);
  margin-bottom: 6px;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.form-select,
.form-input {
  width: 100%;
  padding: 12px 16px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text);
  font-size: 0.95rem;
  transition: border-color var(--transition);
  min-height: 48px;
}

.form-select:focus,
.form-input:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 3px var(--accent-bg);
}

.form-select { appearance: none; cursor: pointer; }

/* ── Tabs (Mi espacio — Sección 11.8) ── */
.tabs {
  display: flex;
  gap: 0;
  border-bottom: 2px solid var(--border);
  margin-bottom: 20px;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
}

.tabs::-webkit-scrollbar { display: none; }

.tab-btn {
  padding: 10px 16px;
  font-size: 0.82rem;
  font-weight: 600;
  color: var(--text-muted);
  border-bottom: 2px solid transparent;
  margin-bottom: -2px;
  white-space: nowrap;
  transition: all var(--transition);
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.tab-btn:hover { color: var(--text-secondary); }

.tab-btn.active {
  color: var(--accent);
  border-bottom-color: var(--accent);
}

.tab-content { display: none; animation: fadeIn 0.25s ease; }
.tab-content.active { display: block; }

/* ── Plan Cards (Sección 11.4) ── */
.plan-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 20px;
  margin-bottom: 12px;
  transition: all var(--transition);
}

.plan-card:hover {
  box-shadow: var(--shadow-md);
  border-color: var(--accent);
}

.plan-card__header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 8px;
}

.plan-card__name {
  font-family: var(--font-display);
  font-size: 1.08rem;
  font-weight: 600;
}

.plan-card__badge {
  font-size: 0.68rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  padding: 3px 10px;
  border-radius: 100px;
  background: var(--accent-bg);
  color: var(--accent);
}

.plan-card__desc {
  font-size: 0.88rem;
  color: var(--text-secondary);
  margin-bottom: 12px;
  line-height: 1.5;
}

.plan-card__meta {
  display: flex;
  gap: 16px;
  font-size: 0.78rem;
  color: var(--text-muted);
  margin-bottom: 14px;
}

.plan-card__meta span {
  display: flex;
  align-items: center;
  gap: 4px;
}

/* ── Reading Display (Sección 11.3) ── */
.reading-header {
  text-align: center;
  margin-bottom: 24px;
  padding-bottom: 20px;
  border-bottom: 1px solid var(--border);
}

.reading-day {
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--accent);
  font-weight: 700;
  margin-bottom: 6px;
}

.reading-title {
  font-family: var(--font-display);
  font-size: 1.35rem;
  font-weight: 600;
  margin-bottom: 4px;
}

.reading-date {
  font-size: 0.82rem;
  color: var(--text-muted);
}

.reading-ref {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 8px 16px;
  background: var(--accent-bg);
  color: var(--accent);
  border-radius: 100px;
  font-size: 0.88rem;
  font-weight: 600;
  margin: 6px 4px;
  transition: all var(--transition);
  cursor: pointer;
}

.reading-ref:hover {
  background: var(--accent);
  color: #FFFFFF;
}

.bible-text {
  font-size: 1.06rem;
  line-height: 1.85;
  color: var(--text);
  padding: 20px 0;
  border-top: 1px solid var(--border-light);
  border-bottom: 1px solid var(--border-light);
  margin: 16px 0;
}

.bible-text .verse-num {
  font-size: 0.68em;
  color: var(--accent);
  font-weight: 700;
  vertical-align: super;
  margin-right: 3px;
  line-height: 0;
}

.bible-text p { margin-bottom: 16px; }

.reading-nav {
  display: flex;
  justify-content: space-between;
  margin-top: 20px;
  gap: 12px;
}

/* ── Search Results ── */
.search-results { margin-top: 16px; }

.search-result-item {
  padding: 16px;
  border-bottom: 1px solid var(--border-light);
  cursor: pointer;
  transition: background var(--transition);
  border-radius: var(--radius-sm);
}

.search-result-item:hover { background: var(--surface-hover); }

.search-result-item:last-child { border-bottom: none; }

.search-result-ref {
  font-weight: 700;
  color: var(--accent);
  font-size: 0.88rem;
  margin-bottom: 4px;
}

.search-result-text {
  font-size: 0.92rem;
  color: var(--text-secondary);
  line-height: 1.5;
}

.search-result-text mark {
  background: var(--accent-bg);
  color: var(--accent);
  padding: 1px 3px;
  border-radius: 3px;
  font-weight: 600;
}

/* ── Mi Espacio Summary ── */
.summary-stats {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
  margin-bottom: 20px;
}

.stat-card {
  text-align: center;
  padding: 16px 8px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
}

.stat-card__number {
  font-family: var(--font-display);
  font-size: 1.6rem;
  font-weight: 700;
  color: var(--accent);
  line-height: 1;
}

.stat-card__label {
  font-size: 0.7rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.04em;
  margin-top: 4px;
}

/* ── FAQ Accordion (Sección 11.10) ── */
.faq-item {
  border-bottom: 1px solid var(--border);
  padding: 0;
}

.faq-question {
  width: 100%;
  text-align: left;
  padding: 16px 0;
  font-weight: 600;
  font-size: 0.95rem;
  color: var(--text);
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  cursor: pointer;
  transition: color var(--transition);
}

.faq-question:hover { color: var(--accent); }

.faq-question i { flex-shrink: 0; transition: transform 0.3s ease; }

.faq-answer {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.35s ease, padding 0.35s ease;
}

.faq-item.open .faq-answer {
  max-height: 300px;
  padding-bottom: 16px;
}

.faq-item.open .faq-question i { transform: rotate(180deg); }

.faq-answer p {
  font-size: 0.9rem;
  color: var(--text-secondary);
  line-height: 1.6;
}

/* ── Install Steps (Sección 18.3) ── */
.install-platform {
  margin-bottom: 28px;
}

.install-platform h3 {
  font-family: var(--font-display);
  font-size: 1.05rem;
  margin-bottom: 14px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.install-steps {
  list-style: none;
  counter-reset: step;
}

.install-steps li {
  counter-increment: step;
  padding: 10px 0 10px 44px;
  position: relative;
  font-size: 0.9rem;
  color: var(--text-secondary);
  line-height: 1.5;
  border-left: 2px solid var(--border);
  margin-left: 14px;
}

.install-steps li::before {
  content: counter(step);
  position: absolute;
  left: -13px;
  top: 10px;
  width: 24px;
  height: 24px;
  background: var(--accent);
  color: #FFFFFF;
  border-radius: 50%;
  font-size: 0.72rem;
  font-weight: 700;
  display: flex;
  align-items: center;
  justify-content: center;
}

.install-steps li:last-child { border-left-color: transparent; }

/* ── About Page (Sección 11.9) ── */
.about-verse {
  font-family: var(--font-display);
  font-style: italic;
  font-size: 1.05rem;
  color: var(--text-secondary);
  padding: 20px 24px;
  border-left: 3px solid var(--accent);
  background: var(--accent-bg);
  border-radius: 0 var(--radius-sm) var(--radius-sm) 0;
  margin: 20px 0;
  line-height: 1.6;
}

.about-verse cite {
  display: block;
  font-style: normal;
  font-family: var(--font-body);
  font-size: 0.82rem;
  color: var(--text-muted);
  margin-top: 8px;
  font-weight: 600;
}

.about-section { margin-bottom: 24px; }

.about-section h3 {
  font-family: var(--font-display);
  font-size: 1.05rem;
  margin-bottom: 8px;
}

.about-section p,
.about-section li {
  font-size: 0.92rem;
  color: var(--text-secondary);
  line-height: 1.65;
}

.about-section ul {
  padding-left: 20px;
  margin-top: 6px;
}

.about-section li { margin-bottom: 6px; }

/* ── Placeholder / Empty States ── */
.placeholder {
  text-align: center;
  padding: 48px 24px;
  color: var(--text-muted);
}

.placeholder i {
  display: block;
  margin: 0 auto 16px;
  opacity: 0.4;
}

.placeholder p {
  font-size: 0.92rem;
  line-height: 1.5;
}

/* ── Loading Spinner ── */
.loading {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 40px;
  color: var(--text-muted);
  gap: 10px;
}

.loading::after {
  content: '';
  width: 20px;
  height: 20px;
  border: 2px solid var(--border);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}

@keyframes spin { to { transform: rotate(360deg); } }

/* ── Quick Actions Grid (Home) ── */
.quick-actions {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  margin-bottom: 24px;
}

.quick-action {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 14px 16px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text);
  font-size: 0.88rem;
  font-weight: 600;
  transition: all var(--transition);
}

.quick-action:hover {
  border-color: var(--accent);
  background: var(--accent-bg);
}

.quick-action i { color: var(--accent); flex-shrink: 0; }

/* ── Footer ── */
.mb-footer {
  text-align: center;
  padding: 24px 16px 100px;
  font-size: 0.78rem;
  color: var(--text-muted);
  max-width: var(--max-width);
  margin: 0 auto;
}

.mb-footer a { color: var(--accent); }

/* ── Responsive ── */

/* Tablet+ */
@media (min-width: 768px) {
  .mb-nav-desktop { display: flex; }
  .mb-bottom-nav { display: none; }
  .mb-main { padding-bottom: 40px; }
  .mb-page { padding: 32px 24px; }
  .page-title { font-size: 2rem; }
  .summary-stats { grid-template-columns: repeat(6, 1fr); }
  .quick-actions { grid-template-columns: repeat(4, 1fr); }
  .daily-verse { padding: 36px 32px; }
  .daily-verse__text { font-size: 1.3rem; }
}

/* Desktop */
@media (min-width: 1024px) {
  .mb-header__inner { max-width: 960px; }
  .mb-page { max-width: 760px; }
}

/* Small phones */
@media (max-width: 374px) {
  .mb-bottom-nav a span { font-size: 0.58rem; }
  .mb-header__brand h1 { font-size: 1rem; }
  .daily-verse { padding: 20px 18px; }
  .daily-verse__text { font-size: 1.05rem; }
  .summary-stats { grid-template-columns: repeat(2, 1fr); }
}

/* ── Utility Classes ── */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0,0,0,0);
  border: 0;
}

.mt-1 { margin-top: 8px; }
.mt-2 { margin-top: 16px; }
.mt-3 { margin-top: 24px; }
.mb-1 { margin-bottom: 8px; }
.mb-2 { margin-bottom: 16px; }
.mb-3 { margin-bottom: 24px; }
.text-center { text-align: center; }
.text-muted { color: var(--text-muted); }
.text-accent { color: var(--accent); }
.flex-center { display: flex; align-items: center; justify-content: center; }
.gap-1 { gap: 8px; }
.gap-2 { gap: 16px; }

body.script:
//

/* ============================================================
   1. APP CONFIGURATION (Sección 8.3)
   ============================================================ */
const APP_CONFIG = {
  name: 'Mi Biblia 365',
  version: '1.0.0',
  cdnBase: 'https://cdn.jsdelivr.net/gh/USUARIO/mibiblia365@main/CDN/',
  primaryApi: 'https://docs-bible-api.netlify.app/api',
  backupApi: 'https://rest.api.bible/v1',
  backupApiKey: 'lKDNAnTqVMi4Mc32rwonP',
  defaultVersion: 'rv1960',
  storageKey: 'mibiblia365_data',
  configKey: 'mibiblia365_config'
};

/* ============================================================
   2. BIBLE SERVICE (Sección 7.3 — bibleService.js)
   ============================================================ */
const BibleService = {
  versionMap: {
    rv1960: { api: 'primary', id: 'rv1960' },
    rv1995: { api: 'primary', id: 'rv1995' },
    nvi:    { api: 'primary', id: 'nvi' },
    dhh:    { api: 'primary', id: 'dhh' },
    pdt:    { api: 'primary', id: 'pdt' },
    ntv:    { api: 'backup',  bibleId: '826f63861180e056-01' },
    nbla:   { api: 'backup',  bibleId: 'ce11b813f9a27e20-01' },
    lbla:   { api: 'backup',  bibleId: 'e3f420b9665abaeb-01' }
  },

  cache: {},

  async getChapter(book, chapter, version) {
    version = version || APP_CONFIG.defaultVersion;
    const cacheKey = version + ':' + book + ':' + chapter;
    if (this.cache[cacheKey]) return this.cache[cacheKey];

    try {
      const data = await this._fetchPrimary(book, chapter, version);
      this.cache[cacheKey] = data;
      return data;
    } catch (e) {
      console.warn('API principal falló, usando respaldo:', e.message);
      try {
        const data = await this._fetchBackup(book, chapter, version);
        this.cache[cacheKey] = data;
        return data;
      } catch (e2) {
        console.error('Ambas APIs fallaron:', e2.message);
        return null;
      }
    }
  },

  async _fetchPrimary(book, chapter, version) {
    const url = APP_CONFIG.primaryApi + '/chapter?book=' + encodeURIComponent(book) + '&chapter=' + chapter + '&version=' + version;
    const res = await fetch(url);
    if (!res.ok) throw new Error('HTTP ' + res.status);
    return await res.json();
  },

  async _fetchBackup(book, chapter, version) {
    const map = this.versionMap[version];
    if (!map || map.api !== 'backup') throw new Error('No hay respaldo para esta versión');
    const url = APP_CONFIG.backupApi + '/bibles/' + map.bibleId + '/search?query=' + encodeURIComponent(book + ' ' + chapter);
    const res = await fetch(url, {
      headers: { 'api-key': APP_CONFIG.backupApiKey }
    });
    if (!res.ok) throw new Error('HTTP ' + res.status);
    return await res.json();
  },

  async search(query, version) {
    version = version || APP_CONFIG.defaultVersion;
    try {
      const url = APP_CONFIG.primaryApi + '/search?query=' + encodeURIComponent(query) + '&version=' + version;
      const res = await fetch(url);
      if (!res.ok) throw new Error('HTTP ' + res.status);
      return await res.json();
    } catch (e) {
      console.error('Error en búsqueda:', e.message);
      return null;
    }
  }
};

/* ============================================================
   3. STORAGE SERVICE (Sección 16.1 — localStorage)
   ============================================================ */
const StorageService = {
  getData() {
    try {
      const raw = localStorage.getItem(APP_CONFIG.storageKey);
      return raw ? JSON.parse(raw) : this._defaultData();
    } catch (e) {
      console.error('Error leyendo localStorage:', e);
      return this._defaultData();
    }
  },

  saveData(data) {
    try {
      data.lastSync = new Date().toISOString();
      localStorage.setItem(APP_CONFIG.storageKey, JSON.stringify(data));
      return true;
    } catch (e) {
      console.error('Error guardando localStorage:', e);
      return false;
    }
  },

  getConfig() {
    try {
      const raw = localStorage.getItem(APP_CONFIG.configKey);
      return raw ? JSON.parse(raw) : this._defaultConfig();
    } catch (e) {
      return this._defaultConfig();
    }
  },

  saveConfig(config) {
    localStorage.setItem(APP_CONFIG.configKey, JSON.stringify(config));
  },

  exportJSON() {
    const data = this.getData();
    const config = this.getConfig();
    const exportObj = {
      version: '1.0',
      exportedAt: new Date().toISOString(),
      app: APP_CONFIG.name,
      data: data,
      config: config
    };
    const blob = new Blob([JSON.stringify(exportObj, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'mibiblia365-respaldo-' + new Date().toISOString().slice(0, 10) + '.json';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  },

  importJSON(file) {
    return new Promise(function(resolve, reject) {
      const reader = new FileReader();
      reader.onload = function(e) {
        try {
          const imported = JSON.parse(e.target.result);
          if (imported.data) {
            localStorage.setItem(APP_CONFIG.storageKey, JSON.stringify(imported.data));
          }
          if (imported.config) {
            localStorage.setItem(APP_CONFIG.configKey, JSON.stringify(imported.config));
          }
          resolve(true);
        } catch (err) {
          reject(err);
        }
      };
      reader.onerror = reject;
      reader.readAsText(file);
    });
  },

  _defaultData() {
    return {
      version: '1.0',
      lastSync: new Date().toISOString(),
      plans: [],
      favorites: [],
      notes: [],
      history: { readings: [], searches: [], chapters: [] }
    };
  },

  _defaultConfig() {
    return {
      preferredVersion: APP_CONFIG.defaultVersion,
      darkMode: false,
      fontSize: 'medium',
      activePlanId: null,
      leapYearMode: 'gracia'
    };
  }
};

/* ============================================================
   4. DATE SERVICE (Sección 9 — Leap year handling)
   ============================================================ */
const DateService = {
  isLeapYear(year) {
    return (year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0);
  },

  getDayOfYear(date) {
    date = date || new Date();
    const start = new Date(date.getFullYear(), 0, 0);
    const diff = date - start;
    const oneDay = 1000 * 60 * 60 * 24;
    return Math.floor(diff / oneDay);
  },

  getPlanDay(startDate, currentDate) {
    var start = new Date(startDate);
    var current = currentDate || new Date();
    var diffMs = current - start;
    var oneDayMs = 1000 * 60 * 60 * 24;
    return Math.floor(diffMs / oneDayMs) + 1;
  },

  formatDate(date) {
    date = date || new Date();
    var months = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
    return date.getDate() + ' de ' + months[date.getMonth()] + ', ' + date.getFullYear();
  },

  isFeb29(date) {
    return date.getMonth() === 1 && date.getDate() === 29;
  }
};

/* ============================================================
   5. PAGE ROUTER (Sección 14.3)
   ============================================================ */
var pages = {
  'home':           { el: 'page-home',           title: 'Inicio' },
  'leer-hoy':       { el: 'page-leer-hoy',       title: 'Leer hoy' },
  'planes':         { el: 'page-planes',         title: 'Planes de lectura' },
  'plan-completo':  { el: 'page-plan-completo',  title: 'Plan completo' },
  'biblia':         { el: 'page-biblia',         title: 'Biblia' },
  'buscar':         { el: 'page-buscar',         title: 'Buscar' },
  'mi-espacio':     { el: 'page-mi-espacio',     title: 'Mi espacio' },
  'acerca':         { el: 'page-acerca',         title: 'Acerca' },
  'faq':            { el: 'page-faq',            title: 'Preguntas frecuentes' },
  'instalar':       { el: 'page-instalar',       title: 'Instalar como app' }
};

function navigateTo(pageId) {
  if (!pages[pageId]) pageId = 'home';

  // Hide all pages
  var allPages = document.querySelectorAll('.mb-page');
  for (var i = 0; i < allPages.length; i++) {
    allPages[i].classList.remove('active');
  }

  // Show target page
  var target = document.getElementById(pages[pageId].el);
  if (target) target.classList.add('active');

  // Update nav active states
  var navLinks = document.querySelectorAll('[data-page]');
  for (var j = 0; j < navLinks.length; j++) {
    navLinks[j].classList.toggle('active', navLinks[j].getAttribute('data-page') === pageId);
  }

  // Update URL hash without scroll
  if (pageId !== 'home') {
    history.pushState(null, '', '/p/' + pageId + '.html');
  } else {
    history.pushState(null, '', '/');
  }

  // Scroll to top
  window.scrollTo({ top: 0, behavior: 'smooth' });

  // Page-specific init
  if (pageId === 'leer-hoy') initLeerHoy();
  if (pageId === 'mi-espacio') initMiEspacio();
}

/* Detect current page from URL on load */
function detectPage() {
  var path = window.location.pathname;
  if (path === '/' || path === '') return 'home';
  var match = path.match(/\/p\/([\w-]+)\.html/);
  if (match && pages[match[1]]) return match[1];
  return 'home';
}

/* Handle browser back/forward */
window.addEventListener('popstate', function() {
  navigateTo(detectPage());
});

/* ============================================================
   6. THEME TOGGLE (Sección 19.3)
   ============================================================ */
function initTheme() {
  var config = StorageService.getConfig();
  if (config.darkMode) {
    document.documentElement.setAttribute('data-theme', 'dark');
    updateThemeIcon(true);
  }

  document.getElementById('theme-toggle').addEventListener('click', function() {
    var isDark = document.documentElement.getAttribute('data-theme') === 'dark';
    if (isDark) {
      document.documentElement.removeAttribute('data-theme');
    } else {
      document.documentElement.setAttribute('data-theme', 'dark');
    }
    updateThemeIcon(!isDark);
    var config = StorageService.getConfig();
    config.darkMode = !isDark;
    StorageService.saveConfig(config);
  });
}

function updateThemeIcon(isDark) {
  var btn = document.getElementById('theme-toggle');
  btn.innerHTML = '';
  var icon = document.createElement('i');
  icon.setAttribute('data-lucide', isDark ? 'sun' : 'moon');
  icon.setAttribute('aria-hidden', 'true');
  btn.appendChild(icon);
  if (window.lucide) lucide.createIcons();
}

/* ============================================================
   7. TABS — MI ESPACIO (Sección 11.8)
   ============================================================ */
function initTabs() {
  var tabBtns = document.querySelectorAll('.tab-btn');
  for (var i = 0; i < tabBtns.length; i++) {
    tabBtns[i].addEventListener('click', function() {
      var tabId = this.getAttribute('data-tab');

      // Deactivate all
      var allBtns = document.querySelectorAll('.tab-btn');
      for (var j = 0; j < allBtns.length; j++) {
        allBtns[j].classList.remove('active');
        allBtns[j].setAttribute('aria-selected', 'false');
      }
      var allContent = document.querySelectorAll('.tab-content');
      for (var k = 0; k < allContent.length; k++) {
        allContent[k].classList.remove('active');
      }

      // Activate target
      this.classList.add('active');
      this.setAttribute('aria-selected', 'true');
      var target = document.getElementById('tab-' + tabId);
      if (target) target.classList.add('active');
    });
  }
}

/* ============================================================
   8. FAQ ACCORDION (Sección 11.10)
   ============================================================ */
function toggleFaq(btn) {
  var item = btn.closest('.faq-item');
  var isOpen = item.classList.contains('open');

  // Close all
  var allItems = document.querySelectorAll('.faq-item');
  for (var i = 0; i < allItems.length; i++) {
    allItems[i].classList.remove('open');
    allItems[i].querySelector('.faq-question').setAttribute('aria-expanded', 'false');
  }

  // Toggle current
  if (!isOpen) {
    item.classList.add('open');
    btn.setAttribute('aria-expanded', 'true');
  }
}

/* ============================================================
   9. LEER HOY — Page Logic (Sección 11.3)
   ============================================================ */
function initLeerHoy() {
  var today = new Date();
  document.getElementById('rh-date').textContent = DateService.formatDate(today);

  // Load config for preferred version
  var config = StorageService.getConfig();
  if (config.preferredVersion) {
    var sel = document.getElementById('rh-version');
    if (sel) sel.value = config.preferredVersion;
  }
}

function loadVerse(ref) {
  // Visual feedback
  var textEl = document.getElementById('rh-text');
  textEl.innerHTML = '<div class="loading">Cargando</div>';

  // In production, this calls BibleService.getChapter()
  // For MVP, show placeholder with loading state
  setTimeout(function() {
    textEl.innerHTML = '<p class="text-muted text-center" style="padding:20px 0">El texto se cargará dinámicamente desde la API bíblica.<br/><br/>Referencia: <strong>' + ref + '</strong></p>';
  }, 500);
}

function changeVersion(version) {
  var config = StorageService.getConfig();
  config.preferredVersion = version;
  StorageService.saveConfig(config);
  // Reload current reading with new version
}

function markAsRead() {
  var btn = document.getElementById('btn-mark-read');
  btn.innerHTML = '<i data-lucide="check" aria-hidden="true"></i> ¡Leído!';
  btn.classList.remove('btn-primary');
  btn.classList.add('btn-secondary');
  btn.style.background = 'var(--success-bg)';
  btn.style.color = 'var(--success)';
  btn.style.borderColor = 'var(--success)';
  if (window.lucide) lucide.createIcons();

  // Update data
  var data = StorageService.getData();
  // In production: update completedDays, streak, lastReadDate
  StorageService.saveData(data);
}

function addFavorite() {
  // In production: prompt for verse selection and save to favorites
  alert('Funcionalidad de favoritos: se guardará el pasaje actual en tu lista de favoritos.');
}

function addNote() {
  // In production: open note editor modal
  var note = prompt('Escribe tu nota para este día:');
  if (note && note.trim()) {
    var data = StorageService.getData();
    data.notes.push({
      id: 'note-' + Date.now(),
      content: note.trim(),
      createdAt: new Date().toISOString(),
      reference: 'Lectura del día'
    });
    StorageService.saveData(data);
    alert('Nota guardada.');
  }
}

function prevDay() { /* Navigate to previous day */ }
function nextDay() { /* Navigate to next day */ }

/* ============================================================
   10. BIBLIA — Book/Chapter Selection (Sección 11.6)
   ============================================================ */
function filterBooks(testament) {
  // In production: show/hide optgroups based on testament
}

function loadChapters(book) {
  if (!book) {
    document.getElementById('chapters-group').style.display = 'none';
    return;
  }
  document.getElementById('chapters-group').style.display = 'block';
  var chapterSel = document.getElementById('biblia-chapter');
  chapterSel.innerHTML = '<option value="">Selecciona un capítulo...</option>';
  // In production: determine chapter count from book data
  var chapterCount = 50; // placeholder
  for (var i = 1; i <= chapterCount; i++) {
    var opt = document.createElement('option');
    opt.value = i;
    opt.textContent = 'Capítulo ' + i;
    chapterSel.appendChild(opt);
  }
}

function loadChapter(chapter) {
  if (!chapter) return;
  var book = document.getElementById('biblia-book').value;
  var version = document.getElementById('biblia-version').value;
  var textEl = document.getElementById('biblia-text');
  textEl.innerHTML = '<div class="loading">Cargando</div>';

  // In production: BibleService.getChapter(book, chapter, version)
  setTimeout(function() {
    textEl.innerHTML = '<p class="text-muted text-center" style="padding:20px 0">El texto de <strong>' + book + ' ' + chapter + '</strong> se cargará desde la API.</p>';
  }, 500);
}

/* ============================================================
   11. SEARCH (Sección 11.7)
   ============================================================ */
function doSearch() {
  var query = document.getElementById('search-input').value.trim();
  if (!query) return;

  var results = document.getElementById('search-results');
  results.innerHTML = '<div class="loading">Buscando</div>';

  // In production: BibleService.search(query, version)
  setTimeout(function() {
    results.innerHTML =
      '<div class="search-result-item" onclick="navigateTo(\'biblia\')">' +
        '<p class="search-result-ref">Juan 3:16</p>' +
        '<p class="search-result-text">Porque de tal manera amó Dios al mundo, que ha dado a su Hijo unigénito, para que todo aquel en él <mark>' + query + '</mark>, no se pierda...</p>' +
      '</div>' +
      '<div class="search-result-item" onclick="navigateTo(\'biblia\')">' +
        '<p class="search-result-ref">1 Corintios 13:4</p>' +
        '<p class="search-result-text">El <mark>' + query + '</mark> es sufrido, es benigno; el <mark>' + query + '</mark> no tiene envidia...</p>' +
      '</div>' +
      '<p class="text-muted text-center mt-2" style="font-size:0.85rem">2 resultados encontrados</p>';
  }, 600);
}

/* ============================================================
   12. MI ESPACIO — Init (Sección 11.8)
   ============================================================ */
function initMiEspacio() {
  var config = StorageService.getConfig();
  if (config.preferredVersion) {
    var sel = document.getElementById('cfg-version');
    if (sel) sel.value = config.preferredVersion;
  }
  if (config.fontSize) {
    var sel2 = document.getElementById('cfg-fontsize');
    if (sel2) sel2.value = config.fontSize;
  }
  if (config.leapYearMode) {
    var sel3 = document.getElementById('cfg-leapyear');
    if (sel3) sel3.value = config.leapYearMode;
  }
}

function saveConfig() {
  var config = StorageService.getConfig();
  config.preferredVersion = document.getElementById('cfg-version').value;
  config.fontSize = document.getElementById('cfg-fontsize').value;
  config.leapYearMode = document.getElementById('cfg-leapyear').value;
  StorageService.saveConfig(config);
  alert('Ajustes guardados.');
}

function exportData() {
  StorageService.exportJSON();
}

function importData(event) {
  var file = event.target.files[0];
  if (!file) return;
  StorageService.importJSON(file).then(function() {
    alert('Datos importados correctamente. La página se recargará.');
    location.reload();
  }).catch(function(err) {
    alert('Error al importar: ' + err.message);
  });
}

/* ============================================================
   13. DAILY VERSE (Sección 10)
   ============================================================ */
function loadDailyVerse() {
  var dayOfYear = DateService.getDayOfYear();
  // In production: fetch from versiculos-diarios.json via CDN
  // For MVP, use static example
  var today = new Date();
  var month = today.getMonth();
  var themes = [
    'Propósito y nuevos comienzos',
    'Amor de Dios y comunión',
    'Crecimiento espiritual',
    'Sacrificio de Cristo y resurrección',
    'Paz y descanso',
    'Fortaleza y ánimo',
    'Sabiduría y guía',
    'Oración',
    'Evangelismo y salvación',
    'Fe y confianza',
    'Gratitud',
    'Navidad, encarnación y gozo'
  ];

  var themeEl = document.getElementById('dv-theme');
  if (themeEl && themes[month]) {
    themeEl.textContent = 'Tema del mes: ' + themes[month];
  }
}

/* ============================================================
   14. APP INITIALIZATION
   ============================================================ */
function initApp() {
  // Detect and navigate to current page
  var currentPage = detectPage();
  navigateTo(currentPage);

  // Initialize theme
  initTheme();

  // Initialize tabs
  initTabs();

  // Load daily verse
  loadDailyVerse();

  // Initialize Lucide icons
  if (window.lucide) {
    lucide.createIcons();
  }

  console.log(APP_CONFIG.name + ' v' + APP_CONFIG.version + ' — inicializado');
}

/* Start app when DOM is ready */
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initApp);
} else {
  initApp();
}

//
